	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://www.collinsdictionary.com/dictionary/german-english/dosen_2"target="target3">dĂ¶sen</a>&nbsp;&nbsp;<a href="https://www.verbformen.com/?w=eind%C3%B6sen"target="target4">eindĂ¶sen</a>',
