'in die Parade fahren': [
	'jmdm. <b>in die Parade fahren</b>: rain on so.\'s parade; bother so.'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.dwds.de/wb/jmdm.%20in%20die%20Parade%20fahren"target="target1">in die Parade fahren</a>&nbsp;&nbsp;<a href="https://www.geo.de/geolino/redewendungen/2497-rtkl-redewendung-jemandem-die-parade-fahren"target="target2">in die Parade fahren</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://www.dict.cc/?s=in+die+Parade+fahren"target="target3">in die Parade fahren</a>&nbsp;&nbsp;<a href="https://context.reverso.net/translation/german-english/in+die+Parade+fahren"target="target4">in die Parade fahren</a>',
	'<u>Lunapark</u>',
	'<i>Rath</i>: "Und deine (<i>GrĂ¤fs</i>) Pfeife mit drei F? (<i>gemeint ist TruppfĂĽhrer Pfeiffer</i>) Die da drĂĽben gerade dem Kollegen Lange <b>in die Parade fĂ¤hrt</b> und die Zeugenvernehmung stĂ¶rt? Hat die auch nur einen blassen Schimmer von Polizeiarbeit?"  (<i>Lunapark</i>, 25)',
	'"Das hier ist seine (<i>Erich Sperlings</i>) Brieftasche", sagte Lange. "Nicht viel drin. Vielleicht doch Raubmord.." "NatĂĽrlich nicht!", unterbrach ihn GrĂ¤f. "Das ist ein politischer Mord! Passt eindeutig in die Reihe." "Nur dass der Tote hier keine Uniform trĂ¤gt", warf Rath ein. Nicht, dass er glaubte, dass der Mord hier nicht in die Reihe passte, er war sich sogar ziemlich sicherÂ â€“ aber es Ă¤rgerte ihn, wie GrĂ¤f dem Kollegen vom Alex (<i>Lange</i>) <b>in die Parade fuhr</b>. (<i>Lunapark</i>, 329)',
	'Reinhold GrĂ¤f saĂź am Vernehmungstisch und stellte seine Fragen. Und hoffte, dass Gereon Rath, der neben der TĂĽr stand, mit verschrĂ¤nkten Armen, ihm bei dieser Vernehmung nicht <b>in die Parade</b> fahren wĂĽrde. (<i>Lunapark</i>, 333)',
],
'Parade (in die P. fahren)': [
	'jmdm. <b>in die Parade fahren</b>: rain on so.\'s parade; bother so.'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.dwds.de/wb/jmdm.%20in%20die%20Parade%20fahren"target="target1">in die Parade fahren</a>&nbsp;&nbsp;<a href="https://www.geo.de/geolino/redewendungen/2497-rtkl-redewendung-jemandem-die-parade-fahren"target="target2">in die Parade fahren</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://www.dict.cc/?s=in+die+Parade+fahren"target="target3">in die Parade fahren</a>&nbsp;&nbsp;<a href="https://context.reverso.net/translation/german-english/in+die+Parade+fahren"target="target4">in die Parade fahren</a>',
	'<u>Lunapark</u>',
	'<i>Rath</i>: "Und deine (<i>GrĂ¤fs</i>) Pfeife mit drei F? (<i>gemeint ist TruppfĂĽhrer Pfeiffer</i>) Die da drĂĽben gerade dem Kollegen Lange <b>in die Parade fĂ¤hrt</b> und die Zeugenvernehmung stĂ¶rt? Hat die auch nur einen blassen Schimmer von Polizeiarbeit?"  (<i>Lunapark</i>, 25)',
	'"Das hier ist seine (<i>Erich Sperlings</i>) Brieftasche", sagte Lange. "Nicht viel drin. Vielleicht doch Raubmord.." "NatĂĽrlich nicht!", unterbrach ihn GrĂ¤f. "Das ist ein politischer Mord! Passt eindeutig in die Reihe." "Nur dass der Tote hier keine Uniform trĂ¤gt", warf Rath ein. Nicht, dass er glaubte, dass der Mord hier nicht in die Reihe passte, er war sich sogar ziemlich sicherÂ â€“ aber es Ă¤rgerte ihn, wie GrĂ¤f dem Kollegen vom Alex (<i>Lange</i>) <b>in die Parade fuhr</b>. (<i>Lunapark</i>, 329)',
	'Reinhold GrĂ¤f saĂź am Vernehmungstisch und stellte seine Fragen. Und hoffte, dass Gereon Rath, der neben der TĂĽr stand, mit verschrĂ¤nkten Armen, ihm bei dieser Vernehmung nicht <b>in die Parade</b> fahren wĂĽrde. (<i>Lunapark</i>, 333)',
],
'ins Haus stehen': [
	'<b>ins Haus stehen</b>: be in store (for sb.), be imminent'+
	'<br>Deutsch:&nbsp;&nbsp;<a href="https://www.dwds.de/wb/ins%20Haus%20stehen"target="target1">ins Haus stehen&nbsp;&nbsp;<a href="https://www.redensarten-index.de/suche.php?suchbegriff=ins+Haus+stehen&bool=relevanz&gawoe=an&sp0=rart_ou&sp1=rart_varianten_ou"target="target2">ins Haus stehen</a>'+
	'<br>English:&nbsp;&nbsp;&nbsp;<a href="https://www.dict.cc/?s=ins+Haus+stehen"target="target3">ins Haus stehen</a>&nbsp;&nbsp;<a href="https://context.reverso.net/translation/german-english/ins+Haus+stehen"target="target4">ins Haus stehen</a>',
	'<u>MĂ¤rzgefallene</u>',
	'<i>Marlow</i>: "Ich kann nicht riskieren, dass du (<i>Leo</i>) ...der SA noch einmal in die HĂ¤nde fĂ¤llst!" Das hatte Leo weiĂź Gott nicht vor. Im Gegenteil. Er wollte, dass die ArschlĂ¶cher <i>ihm</i> in die HĂ¤nde fielen. Die ArschlĂ¶cher, die ihm das angetan hatten.... All die MĂ¤nner auf der Liste in seinem Kopf, denen noch eine unliebsame Begegnung mit Leo Jurezka <b>ins Haus stand</b>. (<i>MĂ¤rzgefallene</i>, 387)',
],
